#include <bits/stdc++.h>
using namespace std;

int n, m;
vector<int> l[100005];
bool v[100005];

void DFS(int x) {
    v[x] = true;
    for (int y : l[x]) {
        if (!v[y]) {
            DFS(y);
        }
    }
}

int main() {
    cin >> n >> m;
    for (int i = 0; i < m; i++) {
        int u, v;
        cin >> u >> v;
        l[u].push_back(v);
        l[v].push_back(u);
    }
    int ans = -1;
    for (int i = 1; i <= n; i++) {
        if (!v[i]) {
            ans++;
            DFS(i);
        }
    }
    cout << ans;
    return 0;
}
